1743 /// Normalize and simplify VPBlendRecipes. Should be run after simplifyRecipes
1744 /// to make sure the masks are simplified.
1745 static void simplifyBlends(VPlan &Plan) {
1746   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
1747            vp_depth_first_shallow(Plan.getVectorLoopRegion()->getEntry()))) {
1748     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
1749       auto *Blend = dyn_cast<VPBlendRecipe>(&R);
1750       if (!Blend)
1751         continue;
1752 
1753       removeCommonBlendMask(Blend);
1754 
1755       // Try to remove redundant blend recipes.
1756       SmallPtrSet<VPValue *, 4> UniqueValues;
1757       if (Blend->isNormalized() || !match(Blend->getMask(0), m_False()))
1758         UniqueValues.insert(Blend->getIncomingValue(0));
1759       for (unsigned I = 1; I != Blend->getNumIncomingValues(); ++I)
1760         if (!match(Blend->getMask(I), m_False()))
1761           UniqueValues.insert(Blend->getIncomingValue(I));
1762 
1763       if (UniqueValues.size() == 1) {
1764         Blend->replaceAllUsesWith(*UniqueValues.begin());
1765         Blend->eraseFromParent();
1766         continue;
1767       }
1768 
1769       if (Blend->isNormalized())
1770         continue;
1771 
1772       // Normalize the blend so its first incoming value is used as the initial
1773       // value with the others blended into it.
1774 
1775       unsigned StartIndex = 0;
1776       for (unsigned I = 0; I != Blend->getNumIncomingValues(); ++I) {
1777         // If a value's mask is used only by the blend then is can be deadcoded.
1778         // TODO: Find the most expensive mask that can be deadcoded, or a mask
1779         // that's used by multiple blends where it can be removed from them all.
1780         VPValue *Mask = Blend->getMask(I);
1781         if (Mask->getNumUsers() == 1 && !match(Mask, m_False())) {
1782           StartIndex = I;
1783           break;
1784         }
1785       }
1786 
1787       SmallVector<VPValue *, 4> OperandsWithMask;
1788       OperandsWithMask.push_back(Blend->getIncomingValue(StartIndex));
1789 
1790       for (unsigned I = 0; I != Blend->getNumIncomingValues(); ++I) {
1791         if (I == StartIndex)
1792           continue;
1793         OperandsWithMask.push_back(Blend->getIncomingValue(I));
1794         OperandsWithMask.push_back(Blend->getMask(I));
1795       }
1796 
1797       auto *NewBlend =
1798           new VPBlendRecipe(cast_or_null<PHINode>(Blend->getUnderlyingValue()),
1799                             OperandsWithMask, *Blend, Blend->getDebugLoc());
1800       NewBlend->insertBefore(&R);
1801 
1802       VPValue *DeadMask = Blend->getMask(StartIndex);
1803       Blend->replaceAllUsesWith(NewBlend);
1804       Blend->eraseFromParent();
1805       recursivelyDeleteDeadRecipes(DeadMask);
