4081 /// This function tries convert extended in-loop reductions to
4082 /// VPExpressionRecipe and clamp the \p Range if it is beneficial and
4083 /// valid. The created recipe must be decomposed to its constituent
4084 /// recipes before execution.
4085 static VPExpressionRecipe *
4086 tryToMatchAndCreateExtendedReduction(VPReductionRecipe *Red, VPCostContext &Ctx,
4087                                      VFRange &Range) {
4088   Type *RedTy = Ctx.Types.inferScalarType(Red);
4089   VPValue *VecOp = Red->getVecOp();
4090 
4091   // Clamp the range if using extended-reduction is profitable.
4092   auto IsExtendedRedValidAndClampRange =
4093       [&](unsigned Opcode, Instruction::CastOps ExtOpc, Type *SrcTy) -> bool {
4094     return LoopVectorizationPlanner::getDecisionAndClampRange(
4095         [&](ElementCount VF) {
4096           auto *SrcVecTy = cast<VectorType>(toVectorTy(SrcTy, VF));
4097           TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
4098 
4099           InstructionCost ExtRedCost = InstructionCost::getInvalid();
4100           InstructionCost ExtCost =
4101               cast<VPWidenCastRecipe>(VecOp)->computeCost(VF, Ctx);
4102           InstructionCost RedCost = Red->computeCost(VF, Ctx);
4103 
4104           if (Red->isPartialReduction()) {
4105             TargetTransformInfo::PartialReductionExtendKind ExtKind =
4106                 TargetTransformInfo::getPartialReductionExtendKind(ExtOpc);
4107             // FIXME: Move partial reduction creation, costing and clamping
4108             // here from LoopVectorize.cpp.
4109             ExtRedCost = Ctx.TTI.getPartialReductionCost(
4110                 Opcode, SrcTy, nullptr, RedTy, VF, ExtKind,
4111                 llvm::TargetTransformInfo::PR_None, std::nullopt, Ctx.CostKind,
4112                 RedTy->isFloatingPointTy()
4113                     ? std::optional{Red->getFastMathFlags()}
4114                     : std::nullopt);
4115           } else if (!RedTy->isFloatingPointTy()) {
4116             // TTI::getExtendedReductionCost only supports integer types.
4117             ExtRedCost = Ctx.TTI.getExtendedReductionCost(
4118                 Opcode, ExtOpc == Instruction::CastOps::ZExt, RedTy, SrcVecTy,
4119                 Red->getFastMathFlags(), CostKind);
4120           }
4121           return ExtRedCost.isValid() && ExtRedCost < ExtCost + RedCost;
4122         },
4123         Range);
4124   };
4125 
4126   VPValue *A;
4127   // Match reduce(ext)).
4128   if (isa<VPWidenCastRecipe>(VecOp) &&
4129       (match(VecOp, m_ZExtOrSExt(m_VPValue(A))) ||
4130        match(VecOp, m_FPExt(m_VPValue(A)))) &&
4131       IsExtendedRedValidAndClampRange(
4132           RecurrenceDescriptor::getOpcode(Red->getRecurrenceKind()),
4133           cast<VPWidenCastRecipe>(VecOp)->getOpcode(),
4134           Ctx.Types.inferScalarType(A)))
4135     return new VPExpressionRecipe(cast<VPWidenCastRecipe>(VecOp), Red);
4136 
4137   return nullptr;
4138 }
