2267 void VPWidenRecipe::execute(VPTransformState &State) {
2268   auto &Builder = State.Builder;
2269   switch (Opcode) {
2270   case Instruction::Call:
2271   case Instruction::Br:
2272   case Instruction::PHI:
2273   case Instruction::GetElementPtr:
2274     llvm_unreachable("This instruction is handled by a different recipe.");
2275   case Instruction::UDiv:
2276   case Instruction::SDiv:
2277   case Instruction::SRem:
2278   case Instruction::URem:
2279   case Instruction::Add:
2280   case Instruction::FAdd:
2281   case Instruction::Sub:
2282   case Instruction::FSub:
2283   case Instruction::FNeg:
2284   case Instruction::Mul:
2285   case Instruction::FMul:
2286   case Instruction::FDiv:
2287   case Instruction::FRem:
2288   case Instruction::Shl:
2289   case Instruction::LShr:
2290   case Instruction::AShr:
2291   case Instruction::And:
2292   case Instruction::Or:
2293   case Instruction::Xor: {
2294     // Just widen unops and binops.
2295     SmallVector<Value *, 2> Ops;
2296     for (VPValue *VPOp : operands())
2297       Ops.push_back(State.get(VPOp));
2298 
2299     Value *V = Builder.CreateNAryOp(Opcode, Ops);
2300 
2301     if (auto *VecOp = dyn_cast<Instruction>(V)) {
2302       applyFlags(*VecOp);
2303       applyMetadata(*VecOp);
2304     }
2305 
2306     // Use this vector value for all users of the original instruction.
2307     State.set(this, V);
2308     break;
2309   }
2310   case Instruction::ExtractValue: {
2311     assert(getNumOperands() == 2 && "expected single level extractvalue");
2312     Value *Op = State.get(getOperand(0));
2313     Value *Extract = Builder.CreateExtractValue(
2314         Op, cast<VPConstantInt>(getOperand(1))->getZExtValue());
2315     State.set(this, Extract);
2316     break;
2317   }
2318   case Instruction::Freeze: {
2319     Value *Op = State.get(getOperand(0));
2320     Value *Freeze = Builder.CreateFreeze(Op);
2321     State.set(this, Freeze);
2322     break;
2323   }
