2765 void VPReductionRecipe::execute(VPTransformState &State) {
2766   assert(!State.Lane && "Reduction being replicated.");
2767   RecurKind Kind = getRecurrenceKind();
2768   assert(!RecurrenceDescriptor::isAnyOfRecurrenceKind(Kind) &&
2769          "In-loop AnyOf reductions aren't currently supported");
2770   // Propagate the fast-math flags carried by the underlying instruction.
2771   IRBuilderBase::FastMathFlagGuard FMFGuard(State.Builder);
2772   State.Builder.setFastMathFlags(getFastMathFlags());
2773   Value *NewVecOp = State.get(getVecOp());
2774   if (VPValue *Cond = getCondOp()) {
2775     Value *NewCond = State.get(Cond, State.VF.isScalar());
2776     VectorType *VecTy = dyn_cast<VectorType>(NewVecOp->getType());
2777     Type *ElementTy = VecTy ? VecTy->getElementType() : NewVecOp->getType();
2778 
2779     Value *Start = getRecurrenceIdentity(Kind, ElementTy, getFastMathFlags());
2780     if (State.VF.isVector())
2781       Start = State.Builder.CreateVectorSplat(VecTy->getElementCount(), Start);
2782 
2783     Value *Select = State.Builder.CreateSelect(NewCond, NewVecOp, Start);
2784     NewVecOp = Select;
2785   }
2786   Value *NewRed;
2787   Value *NextInChain;
2788   if (isOrdered()) {
2789     Value *PrevInChain = State.get(getChainOp(), /*IsScalar*/ true);
2790     if (State.VF.isVector())
2791       NewRed =
2792           createOrderedReduction(State.Builder, Kind, NewVecOp, PrevInChain);
2793     else
2794       NewRed = State.Builder.CreateBinOp(
2795           (Instruction::BinaryOps)RecurrenceDescriptor::getOpcode(Kind),
2796           PrevInChain, NewVecOp);
2797     PrevInChain = NewRed;
2798     NextInChain = NewRed;
2799   } else if (isPartialReduction()) {
2800     assert((Kind == RecurKind::Add || Kind == RecurKind::FAdd) &&
2801            "Unexpected partial reduction kind");
2802     Value *PrevInChain = State.get(getChainOp(), /*IsScalar*/ false);
2803     NewRed = State.Builder.CreateIntrinsic(
2804         PrevInChain->getType(),
2805         Kind == RecurKind::Add ? Intrinsic::vector_partial_reduce_add
2806                                : Intrinsic::vector_partial_reduce_fadd,
2807         {PrevInChain, NewVecOp}, State.Builder.getFastMathFlags(),
2808         "partial.reduce");
2809     PrevInChain = NewRed;
2810     NextInChain = NewRed;
2811   } else {
2812     assert(isInLoop() &&
2813            "The reduction must either be ordered, partial or in-loop");
2814     Value *PrevInChain = State.get(getChainOp(), /*IsScalar*/ true);
2815     NewRed = createSimpleReduction(State.Builder, NewVecOp, Kind);
2816     if (RecurrenceDescriptor::isMinMaxRecurrenceKind(Kind))
2817       NextInChain = createMinMaxOp(State.Builder, Kind, NewRed, PrevInChain);
2818     else
2819       NextInChain = State.Builder.CreateBinOp(
2820           (Instruction::BinaryOps)RecurrenceDescriptor::getOpcode(Kind),
2821           PrevInChain, NewRed);
2822   }
2823   State.set(this, NextInChain, /*IsScalar*/ !isPartialReduction());
2824 }
