2860 InstructionCost VPReductionRecipe::computeCost(ElementCount VF,
2861                                                VPCostContext &Ctx) const {
2862   RecurKind RdxKind = getRecurrenceKind();
2863   Type *ElementTy = Ctx.Types.inferScalarType(this);
2864   auto *VectorTy = cast<VectorType>(toVectorTy(ElementTy, VF));
2865   unsigned Opcode = RecurrenceDescriptor::getOpcode(RdxKind);
2866   FastMathFlags FMFs = getFastMathFlags();
2867   std::optional<FastMathFlags> OptionalFMF =
2868       ElementTy->isFloatingPointTy() ? std::make_optional(FMFs) : std::nullopt;
2869 
2870   if (isPartialReduction()) {
2871     InstructionCost CondCost = 0;
2872     if (isConditional()) {
2873       CmpInst::Predicate Pred = CmpInst::BAD_ICMP_PREDICATE;
2874       auto *CondTy = cast<VectorType>(
2875           toVectorTy(Ctx.Types.inferScalarType(getCondOp()), VF));
2876       CondCost = Ctx.TTI.getCmpSelInstrCost(Instruction::Select, VectorTy,
2877                                             CondTy, Pred, Ctx.CostKind);
2878     }
2879     return CondCost + Ctx.TTI.getPartialReductionCost(
2880                           Opcode, ElementTy, ElementTy, ElementTy, VF,
2881                           TTI::PR_None, TTI::PR_None, {}, Ctx.CostKind,
2882                           OptionalFMF);
2883   }
2884 
2885   // TODO: Support any-of reductions.
2886   assert(
2887       (!RecurrenceDescriptor::isAnyOfRecurrenceKind(RdxKind) ||
2888        ForceTargetInstructionCost.getNumOccurrences() > 0) &&
2889       "Any-of reduction not implemented in VPlan-based cost model currently.");
2890 
2891   // Note that TTI should model the cost of moving result to the scalar register
2892   // and the BinOp cost in the getMinMaxReductionCost().
2893   if (RecurrenceDescriptor::isMinMaxRecurrenceKind(RdxKind)) {
2894     Intrinsic::ID Id = getMinMaxReductionIntrinsicOp(RdxKind);
2895     return Ctx.TTI.getMinMaxReductionCost(Id, VectorTy, FMFs, Ctx.CostKind);
2896   }
2897 
2898   // Note that TTI should model the cost of moving result to the scalar register
2899   // and the BinOp cost in the getArithmeticReductionCost().
2900   return Ctx.TTI.getArithmeticReductionCost(Opcode, VectorTy, OptionalFMF,
2901                                             Ctx.CostKind);
2902 }
