1673   PHINode *Phi = &getIRPhi();
1674   for (const auto &[Idx, Op] : enumerate(operands())) {
1675     VPValue *ExitValue = Op;
1676     auto Lane = vputils::isSingleScalar(ExitValue)
1677                     ? VPLane::getFirstLane()
1678                     : VPLane::getLastLaneForVF(State.VF);
1679     VPBlockBase *Pred = getParent()->getPredecessors()[Idx];
1680     auto *PredVPBB = Pred->getExitingBasicBlock();
1681     BasicBlock *PredBB = State.CFG.VPBB2IRBB[PredVPBB];
1682     // Set insertion point in PredBB in case an extract needs to be generated.
1683     // TODO: Model extracts explicitly.
1684     State.Builder.SetInsertPoint(PredBB->getTerminator());
1685     Value *V = State.get(ExitValue, VPLane(Lane));
1686     // If there is no existing block for PredBB in the phi, add a new incoming
1687     // value. Otherwise update the existing incoming value for PredBB.
1688     if (Phi->getBasicBlockIndex(PredBB) == -1)
