1844 void VPWidenIntrinsicRecipe::execute(VPTransformState &State) {
1845   assert(State.VF.isVector() && "not widening");
1846 
1847   SmallVector<Type *, 2> TysForDecl;
1848   // Add return type if intrinsic is overloaded on it.
1849   if (isVectorIntrinsicWithOverloadTypeAtArg(VectorIntrinsicID, -1,
1850                                              State.TTI)) {
1851     Type *RetTy = toVectorizedTy(getResultType(), State.VF);
1852     append_range(TysForDecl, getContainedTypes(RetTy));
1853   }
1854   SmallVector<Value *, 4> Args;
1855   for (const auto &I : enumerate(operands())) {
1856     // Some intrinsics have a scalar argument - don't replace it with a
1857     // vector.
1858     Value *Arg;
1859     if (isVectorIntrinsicWithScalarOpAtArg(VectorIntrinsicID, I.index(),
1860                                            State.TTI))
1861       Arg = State.get(I.value(), VPLane(0));
1862     else
1863       Arg = State.get(I.value(), usesFirstLaneOnly(I.value()));
1864     if (isVectorIntrinsicWithOverloadTypeAtArg(VectorIntrinsicID, I.index(),
1865                                                State.TTI))
1866       TysForDecl.push_back(Arg->getType());
1867     Args.push_back(Arg);
1868   }
1869 
1870   // Use vector version of the intrinsic.
1871   Module *M = State.Builder.GetInsertBlock()->getModule();
1872   Function *VectorF =
1873       Intrinsic::getOrInsertDeclaration(M, VectorIntrinsicID, TysForDecl);
1874   assert(VectorF &&
1875          "Can't retrieve vector intrinsic or vector-predication intrinsics.");
1876 
1877   auto *CI = cast_or_null<CallInst>(getUnderlyingValue());
1878   SmallVector<OperandBundleDef, 1> OpBundles;
1879   if (CI)
1880     CI->getOperandBundlesAsDefs(OpBundles);
1881 
1882   CallInst *V = State.Builder.CreateCall(VectorF, Args, OpBundles);
1883 
1884   applyFlags(*V);
1885   applyMetadata(*V);
1886 
1887   if (!V->getType()->isVoidTy())
1888     State.set(this, V);
1889 }
