1891 /// Compute the cost for the intrinsic \p ID with \p Operands, produced by \p R.
1892 static InstructionCost getCostForIntrinsics(Intrinsic::ID ID,
1893                                             ArrayRef<const VPValue *> Operands,
1894                                             const VPRecipeWithIRFlags &R,
1895                                             ElementCount VF,
1896                                             VPCostContext &Ctx) {
1897   // Some backends analyze intrinsic arguments to determine cost. Use the
1898   // underlying value for the operand if it has one. Otherwise try to use the
1899   // operand of the underlying call instruction, if there is one. Otherwise
1900   // clear Arguments.
1901   // TODO: Rework TTI interface to be independent of concrete IR values.
1902   SmallVector<const Value *> Arguments;
1903   for (const auto &[Idx, Op] : enumerate(Operands)) {
1904     auto *V = Op->getUnderlyingValue();
1905     if (!V) {
1906       if (auto *UI = dyn_cast_or_null<CallBase>(R.getUnderlyingValue())) {
1907         Arguments.push_back(UI->getArgOperand(Idx));
1908         continue;
1909       }
1910       Arguments.clear();
1911       break;
1912     }
1913     Arguments.push_back(V);
1914   }
1915 
1916   Type *ScalarRetTy = Ctx.Types.inferScalarType(&R);
1917   Type *RetTy = VF.isVector() ? toVectorizedTy(ScalarRetTy, VF) : ScalarRetTy;
1918   SmallVector<Type *> ParamTys;
1919   for (const VPValue *Op : Operands) {
1920     ParamTys.push_back(VF.isVector()
1921                            ? toVectorTy(Ctx.Types.inferScalarType(Op), VF)
1922                            : Ctx.Types.inferScalarType(Op));
1923   }
1924 
1925   // TODO: Rework TTI interface to avoid reliance on underlying IntrinsicInst.
1926   FastMathFlags FMF =
1927       R.hasFastMathFlags() ? R.getFastMathFlags() : FastMathFlags();
1928   IntrinsicCostAttributes CostAttrs(
1929       ID, RetTy, Arguments, ParamTys, FMF,
1930       dyn_cast_or_null<IntrinsicInst>(R.getUnderlyingValue()),
1931       InstructionCost::getInvalid(), &Ctx.TLI);
1932   return Ctx.TTI.getIntrinsicInstrCost(CostAttrs, Ctx.CostKind);
1933 }
1934 
1935 InstructionCost VPWidenIntrinsicRecipe::computeCost(ElementCount VF,
1936                                                     VPCostContext &Ctx) const {
1937   SmallVector<const VPValue *> ArgOps(operands());
1938   return getCostForIntrinsics(VectorIntrinsicID, ArgOps, *this, VF, Ctx);
1939 }
