1976 void VPHistogramRecipe::execute(VPTransformState &State) {
1977   IRBuilderBase &Builder = State.Builder;
1978 
1979   Value *Address = State.get(getOperand(0));
1980   Value *IncAmt = State.get(getOperand(1), /*IsScalar=*/true);
1981   VectorType *VTy = cast<VectorType>(Address->getType());
1982 
1983   // The histogram intrinsic requires a mask even if the recipe doesn't;
1984   // if the mask operand was omitted then all lanes should be executed and
1985   // we just need to synthesize an all-true mask.
1986   Value *Mask = nullptr;
1987   if (VPValue *VPMask = getMask())
1988     Mask = State.get(VPMask);
1989   else
1990     Mask =
1991         Builder.CreateVectorSplat(VTy->getElementCount(), Builder.getInt1(1));
1992 
1993   // If this is a subtract, we want to invert the increment amount. We may
1994   // add a separate intrinsic in future, but for now we'll try this.
1995   if (Opcode == Instruction::Sub)
1996     IncAmt = Builder.CreateNeg(IncAmt);
1997   else
1998     assert(Opcode == Instruction::Add && "only add or sub supported for now");
1999 
2000   State.Builder.CreateIntrinsic(Intrinsic::experimental_vector_histogram_add,
2001                                 {VTy, IncAmt->getType()},
2002                                 {Address, IncAmt, Mask});
2003 }
2004 
2005 InstructionCost VPHistogramRecipe::computeCost(ElementCount VF,
2006                                                VPCostContext &Ctx) const {
2007   // FIXME: Take the gather and scatter into account as well. For now we're
2008   //        generating the same cost as the fallback path, but we'll likely
2009   //        need to create a new TTI method for determining the cost, including
2010   //        whether we can use base + vec-of-smaller-indices or just
2011   //        vec-of-pointers.
2012   assert(VF.isVector() && "Invalid VF for histogram cost");
2013   Type *AddressTy = Ctx.Types.inferScalarType(getOperand(0));
2014   VPValue *IncAmt = getOperand(1);
2015   Type *IncTy = Ctx.Types.inferScalarType(IncAmt);
2016   VectorType *VTy = VectorType::get(IncTy, VF);
2017 
2018   // Assume that a non-constant update value (or a constant != 1) requires
2019   // a multiply, and add that into the cost.
2020   InstructionCost MulCost =
2021       Ctx.TTI.getArithmeticInstrCost(Instruction::Mul, VTy, Ctx.CostKind);
2022   if (auto *CI = dyn_cast<VPConstantInt>(IncAmt))
2023     if (CI->isOne())
2024       MulCost = TTI::TCC_Free;
2025 
2026   // Find the cost of the histogram operation itself.
2027   Type *PtrTy = VectorType::get(AddressTy, VF);
2028   Type *MaskTy = VectorType::get(Type::getInt1Ty(Ctx.LLVMCtx), VF);
2029   IntrinsicCostAttributes ICA(Intrinsic::experimental_vector_histogram_add,
2030                               Type::getVoidTy(Ctx.LLVMCtx),
2031                               {PtrTy, IncTy, MaskTy});
2032 
2033   // Add the costs together with the add/sub operation.
2034   return Ctx.TTI.getIntrinsicInstrCost(ICA, Ctx.CostKind) + MulCost +
2035          Ctx.TTI.getArithmeticInstrCost(Opcode, VTy, Ctx.CostKind);
2036 }
