537 Value *VPInstruction::generate(VPTransformState &State) {
538   IRBuilderBase &Builder = State.Builder;
539 
540   if (Instruction::isBinaryOp(getOpcode())) {
541     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
542     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
543     Value *B = State.get(getOperand(1), OnlyFirstLaneUsed);
544     auto *Res =
545         Builder.CreateBinOp((Instruction::BinaryOps)getOpcode(), A, B, Name);
546     if (auto *I = dyn_cast<Instruction>(Res))
547       applyFlags(*I);
548     return Res;
549   }
550 
551   switch (getOpcode()) {
552   case VPInstruction::Not: {
553     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
554     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
555     return Builder.CreateNot(A, Name);
556   }
557   case Instruction::ExtractElement: {
558     assert(State.VF.isVector() && "Only extract elements from vectors");
559     if (auto *Idx = dyn_cast<VPConstantInt>(getOperand(1)))
560       return State.get(getOperand(0), VPLane(Idx->getZExtValue()));
561     Value *Vec = State.get(getOperand(0));
562     Value *Idx = State.get(getOperand(1), /*IsScalar=*/true);
563     return Builder.CreateExtractElement(Vec, Idx, Name);
564   }
565   case Instruction::Freeze: {
566     Value *Op = State.get(getOperand(0), vputils::onlyFirstLaneUsed(this));
567     return Builder.CreateFreeze(Op, Name);
568   }
569   case Instruction::FCmp:
570   case Instruction::ICmp: {
571     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
572     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
573     Value *B = State.get(getOperand(1), OnlyFirstLaneUsed);
574     return Builder.CreateCmp(getPredicate(), A, B, Name);
575   }
576   case Instruction::PHI: {
577     llvm_unreachable("should be handled by VPPhi::execute");
578   }
579   case Instruction::Select: {
580     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
581     Value *Cond =
582         State.get(getOperand(0),
583                   OnlyFirstLaneUsed || vputils::isSingleScalar(getOperand(0)));
584     Value *Op1 = State.get(getOperand(1), OnlyFirstLaneUsed);
585     Value *Op2 = State.get(getOperand(2), OnlyFirstLaneUsed);
586     FastMathFlags FMFs =
587         hasFastMathFlags() ? getFastMathFlags() : FastMathFlags();
588     return Builder.CreateSelectFMF(Cond, Op1, Op2, FMFs, Name);
589   }
590   case VPInstruction::ActiveLaneMask: {
591     // Get first lane of vector induction variable.
592     Value *VIVElem0 = State.get(getOperand(0), VPLane(0));
593     // Get the original loop tripcount.
594     Value *ScalarTC = State.get(getOperand(1), VPLane(0));
595 
596     // If this part of the active lane mask is scalar, generate the CMP directly
597     // to avoid unnecessary extracts.
598     if (State.VF.isScalar())
599       return Builder.CreateCmp(CmpInst::Predicate::ICMP_ULT, VIVElem0, ScalarTC,
600                                Name);
601 
602     ElementCount EC = State.VF.multiplyCoefficientBy(
603         cast<VPConstantInt>(getOperand(2))->getZExtValue());
604     auto *PredTy = VectorType::get(Builder.getInt1Ty(), EC);
605     return Builder.CreateIntrinsic(Intrinsic::get_active_lane_mask,
606                                    {PredTy, ScalarTC->getType()},
607                                    {VIVElem0, ScalarTC}, nullptr, Name);
608   }
609   case VPInstruction::FirstOrderRecurrenceSplice: {
610     // Generate code to combine the previous and current values in vector v3.
611     //
612     //   vector.ph:
613     //     v_init = vector(..., ..., ..., a[-1])
614     //     br vector.body
615     //
616     //   vector.body
617     //     i = phi [0, vector.ph], [i+4, vector.body]
618     //     v1 = phi [v_init, vector.ph], [v2, vector.body]
619     //     v2 = a[i, i+1, i+2, i+3];
620     //     v3 = vector(v1(3), v2(0, 1, 2))
621 
622     auto *V1 = State.get(getOperand(0));
623     if (!V1->getType()->isVectorTy())
624       return V1;
625     Value *V2 = State.get(getOperand(1));
626     return Builder.CreateVectorSpliceRight(V1, V2, 1, Name);
627   }
628   case VPInstruction::CalculateTripCountMinusVF: {
629     unsigned UF = getParent()->getPlan()->getUF();
630     Value *ScalarTC = State.get(getOperand(0), VPLane(0));
631     Value *Step = createStepForVF(Builder, ScalarTC->getType(), State.VF, UF);
632     Value *Sub = Builder.CreateSub(ScalarTC, Step);
633     Value *Cmp = Builder.CreateICmp(CmpInst::Predicate::ICMP_UGT, ScalarTC, Step);
634     Value *Zero = ConstantInt::getNullValue(ScalarTC->getType());
635     return Builder.CreateSelect(Cmp, Sub, Zero);
636   }
637   case VPInstruction::ExplicitVectorLength: {
638     // TODO: Restructure this code with an explicit remainder loop, vsetvli can
639     // be outside of the main loop.
640     Value *AVL = State.get(getOperand(0), /*IsScalar*/ true);
641     // Compute EVL
642     assert(AVL->getType()->isIntegerTy() &&
643            "Requested vector length should be an integer.");
644 
645     assert(State.VF.isScalable() && "Expected scalable vector factor.");
646     Value *VFArg = Builder.getInt32(State.VF.getKnownMinValue());
647 
648     Value *EVL = Builder.CreateIntrinsic(
649         Builder.getInt32Ty(), Intrinsic::experimental_get_vector_length,
650         {AVL, VFArg, Builder.getTrue()});
651     return EVL;
652   }
653   case VPInstruction::CanonicalIVIncrementForPart: {
654     unsigned Part = getUnrollPart(*this);
655     auto *IV = State.get(getOperand(0), VPLane(0));
656     assert(Part != 0 && "Must have a positive part");
657     // The canonical IV is incremented by the vectorization factor (num of
658     // SIMD elements) times the unroll part.
659     Value *Step = createStepForVF(Builder, IV->getType(), State.VF, Part);
660     return Builder.CreateAdd(IV, Step, Name, hasNoUnsignedWrap(),
661                              hasNoSignedWrap());
662   }
663   case VPInstruction::BranchOnCond: {
664     Value *Cond = State.get(getOperand(0), VPLane(0));
665     // Replace the temporary unreachable terminator with a new conditional
666     // branch, hooking it up to backward destination for latch blocks now, and
667     // to forward destination(s) later when they are created.
668     // Second successor may be backwards - iff it is already in VPBB2IRBB.
669     VPBasicBlock *SecondVPSucc =
670         cast<VPBasicBlock>(getParent()->getSuccessors()[1]);
671     BasicBlock *SecondIRSucc = State.CFG.VPBB2IRBB.lookup(SecondVPSucc);
672     BasicBlock *IRBB = State.CFG.VPBB2IRBB[getParent()];
673     auto *Br = Builder.CreateCondBr(Cond, IRBB, SecondIRSucc);
674     // First successor is always forward, reset it to nullptr.
675     Br->setSuccessor(0, nullptr);
676     IRBB->getTerminator()->eraseFromParent();
677     applyMetadata(*Br);
678     return Br;
679   }
680   case VPInstruction::Broadcast: {
681     return Builder.CreateVectorSplat(
682         State.VF, State.get(getOperand(0), /*IsScalar*/ true), "broadcast");
683   }
684   case VPInstruction::BuildStructVector: {
685     // For struct types, we need to build a new 'wide' struct type, where each
686     // element is widened, i.e., we create a struct of vectors.
687     auto *StructTy =
688         cast<StructType>(State.TypeAnalysis.inferScalarType(getOperand(0)));
689     Value *Res = PoisonValue::get(toVectorizedTy(StructTy, State.VF));
690     for (const auto &[LaneIndex, Op] : enumerate(operands())) {
691       for (unsigned FieldIndex = 0; FieldIndex != StructTy->getNumElements();
692            FieldIndex++) {
693         Value *ScalarValue =
694             Builder.CreateExtractValue(State.get(Op, true), FieldIndex);
695         Value *VectorValue = Builder.CreateExtractValue(Res, FieldIndex);
696         VectorValue =
697             Builder.CreateInsertElement(VectorValue, ScalarValue, LaneIndex);
698         Res = Builder.CreateInsertValue(Res, VectorValue, FieldIndex);
699       }
700     }
701     return Res;
702   }
703   case VPInstruction::BuildVector: {
704     auto *ScalarTy = State.TypeAnalysis.inferScalarType(getOperand(0));
705     auto NumOfElements = ElementCount::getFixed(getNumOperands());
706     Value *Res = PoisonValue::get(toVectorizedTy(ScalarTy, NumOfElements));
707     for (const auto &[Idx, Op] : enumerate(operands()))
708       Res = Builder.CreateInsertElement(Res, State.get(Op, true),
709                                         Builder.getInt32(Idx));
710     return Res;
711   }
712   case VPInstruction::ReductionStartVector: {
713     if (State.VF.isScalar())
714       return State.get(getOperand(0), true);
715     IRBuilderBase::FastMathFlagGuard FMFG(Builder);
716     Builder.setFastMathFlags(getFastMathFlags());
717     // If this start vector is scaled then it should produce a vector with fewer
718     // elements than the VF.
719     ElementCount VF = State.VF.divideCoefficientBy(
720         cast<VPConstantInt>(getOperand(2))->getZExtValue());
721     auto *Iden = Builder.CreateVectorSplat(VF, State.get(getOperand(1), true));
722     return Builder.CreateInsertElement(Iden, State.get(getOperand(0), true),
723                                        Builder.getInt32(0));
724   }
725   case VPInstruction::ComputeAnyOfResult: {
726     Value *Start = State.get(getOperand(0), VPLane(0));
727     Value *NewVal = State.get(getOperand(1), VPLane(0));
728     Value *ReducedResult = State.get(getOperand(2));
729     for (unsigned Idx = 3; Idx < getNumOperands(); ++Idx)
730       ReducedResult =
731           Builder.CreateBinOp(Instruction::Or, State.get(getOperand(Idx)),
732                               ReducedResult, "bin.rdx");
733     // If any predicate is true it means that we want to select the new value.
734     if (ReducedResult->getType()->isVectorTy())
735       ReducedResult = Builder.CreateOrReduce(ReducedResult);
736     // The compares in the loop may yield poison, which propagates through the
737     // bitwise ORs. Freeze it here before the condition is used.
738     ReducedResult = Builder.CreateFreeze(ReducedResult);
739     return Builder.CreateSelect(ReducedResult, NewVal, Start, "rdx.select");
740   }
741   case VPInstruction::ComputeReductionResult: {
742     RecurKind RK = getRecurKind();
743     bool IsOrdered = isReductionOrdered();
744     bool IsInLoop = isReductionInLoop();
745     assert(!RecurrenceDescriptor::isFindIVRecurrenceKind(RK) &&
746            "FindIV should use min/max reduction kinds");
747 
748     // The recipe may have multiple operands to be reduced together.
749     unsigned NumOperandsToReduce = getNumOperands();
