2373 InstructionCost VPWidenRecipe::computeCost(ElementCount VF,
2374                                            VPCostContext &Ctx) const {
2375   switch (Opcode) {
2376   case Instruction::UDiv:
2377   case Instruction::SDiv:
2378   case Instruction::SRem:
2379   case Instruction::URem:
2380     // If the div/rem operation isn't safe to speculate and requires
2381     // predication, then the only way we can even create a vplan is to insert
2382     // a select on the second input operand to ensure we use the value of 1
2383     // for the inactive lanes. The select will be costed separately.
2384   case Instruction::FNeg:
2385   case Instruction::Add:
2386   case Instruction::FAdd:
2387   case Instruction::Sub:
2388   case Instruction::FSub:
2389   case Instruction::Mul:
2390   case Instruction::FMul:
2391   case Instruction::FDiv:
2392   case Instruction::FRem:
2393   case Instruction::Shl:
2394   case Instruction::LShr:
2395   case Instruction::AShr:
2396   case Instruction::And:
2397   case Instruction::Or:
2398   case Instruction::Xor:
2399   case Instruction::Freeze:
2400   case Instruction::ExtractValue:
2401   case Instruction::ICmp:
2402   case Instruction::FCmp:
2403   case Instruction::Select:
2404     return getCostForRecipeWithOpcode(getOpcode(), VF, Ctx);
2405   default:
2406     llvm_unreachable("Unsupported opcode for instruction");
2407   }
