2518 void VPScalarIVStepsRecipe::execute(VPTransformState &State) {
2519   // Fast-math-flags propagate from the original induction instruction.
2520   IRBuilder<>::FastMathFlagGuard FMFG(State.Builder);
2521   if (hasFastMathFlags())
2522     State.Builder.setFastMathFlags(getFastMathFlags());
2523 
2524   /// Compute scalar induction steps. \p ScalarIV is the scalar induction
2525   /// variable on which to base the steps, \p Step is the size of the step.
2526 
2527   Value *BaseIV = State.get(getOperand(0), VPLane(0));
2528   Value *Step = State.get(getStepValue(), VPLane(0));
2529   IRBuilderBase &Builder = State.Builder;
2530 
2531   // Ensure step has the same type as that of scalar IV.
2532   Type *BaseIVTy = BaseIV->getType()->getScalarType();
2533   assert(BaseIVTy == Step->getType() && "Types of BaseIV and Step must match!");
2534 
2535   // We build scalar steps for both integer and floating-point induction
2536   // variables. Here, we determine the kind of arithmetic we will perform.
2537   Instruction::BinaryOps AddOp;
2538   Instruction::BinaryOps MulOp;
2539   if (BaseIVTy->isIntegerTy()) {
2540     AddOp = Instruction::Add;
2541     MulOp = Instruction::Mul;
2542   } else {
2543     AddOp = InductionOpcode;
2544     MulOp = Instruction::FMul;
2545   }
2546 
2547   // Determine the number of scalars we need to generate.
2548   bool FirstLaneOnly = vputils::onlyFirstLaneUsed(this);
2549   // Compute the scalar steps and save the results in State.
2550 
2551   unsigned StartLane = 0;
2552   unsigned EndLane = FirstLaneOnly ? 1 : State.VF.getKnownMinValue();
2553   if (State.Lane) {
2554     StartLane = State.Lane->getKnownLane();
2555     EndLane = StartLane + 1;
2556   }
2557   Value *StartIdx0 = getStartIndex() ? State.get(getStartIndex(), true)
2558                                      : Constant::getNullValue(BaseIVTy);
2559 
2560   for (unsigned Lane = StartLane; Lane < EndLane; ++Lane) {
2561     // It is okay if the induction variable type cannot hold the lane number,
2562     // we expect truncation in this case.
2563     Constant *LaneValue =
2564         BaseIVTy->isIntegerTy()
2565             ? ConstantInt::get(BaseIVTy, Lane, /*IsSigned=*/false,
2566                                /*ImplicitTrunc=*/true)
2567             : ConstantFP::get(BaseIVTy, Lane);
2568     Value *StartIdx = Builder.CreateBinOp(AddOp, StartIdx0, LaneValue);
2569     // The step returned by `createStepForVF` is a runtime-evaluated value
2570     // when VF is scalable. Otherwise, it should be folded into a Constant.
2571     assert((State.VF.isScalable() || isa<Constant>(StartIdx)) &&
2572            "Expected StartIdx to be folded to a constant when VF is not "
2573            "scalable");
2574     auto *Mul = Builder.CreateBinOp(MulOp, StartIdx, Step);
2575     auto *Add = Builder.CreateBinOp(AddOp, BaseIV, Mul);
2576     State.set(this, Add, VPLane(Lane));
2577   }
2578 }
