1613 static void narrowToSingleScalarRecipes(VPlan &Plan) {
1614   if (Plan.hasScalarVFOnly())
1615     return;
1616 
1617   // Try to narrow wide and replicating recipes to single scalar recipes,
1618   // based on VPlan analysis. Only process blocks in the loop region for now,
1619   // without traversing into nested regions, as recipes in replicate regions
1620   // cannot be converted yet.
1621   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
1622            vp_depth_first_shallow(Plan.getVectorLoopRegion()->getEntry()))) {
1623     for (VPRecipeBase &R : make_early_inc_range(reverse(*VPBB))) {
1624       if (!isa<VPWidenRecipe, VPWidenGEPRecipe, VPReplicateRecipe,
1625                VPWidenStoreRecipe>(&R))
1626         continue;
1627       auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
1628       if (RepR && (RepR->isSingleScalar() || RepR->isPredicated()))
1629         continue;
1630 
1631       // Convert an unmasked scatter with an uniform address into
1632       // extract-last-lane + scalar store.
1633       // TODO: Add a profitability check comparing the cost of a scatter vs.
1634       // extract + scalar store.
1635       auto *WidenStoreR = dyn_cast<VPWidenStoreRecipe>(&R);
1636       if (WidenStoreR && vputils::isSingleScalar(WidenStoreR->getAddr()) &&
1637           !WidenStoreR->isConsecutive()) {
1638         assert(!WidenStoreR->isReverse() &&
1639                "Not consecutive memory recipes shouldn't be reversed");
1640         VPValue *Mask = WidenStoreR->getMask();
1641 
1642         // Only convert the scatter to a scalar store if it is unmasked.
1643         // TODO: Support converting scatter masked by the header mask to scalar
1644         // store.
1645         if (Mask)
1646           continue;
1647 
1648         auto *Extract = new VPInstruction(VPInstruction::ExtractLastLane,
1649                                           {WidenStoreR->getOperand(1)});
1650         Extract->insertBefore(WidenStoreR);
1651 
1652         // TODO: Sink the scalar store recipe to middle block if possible.
1653         auto *ScalarStore = new VPReplicateRecipe(
1654             &WidenStoreR->getIngredient(), {Extract, WidenStoreR->getAddr()},
1655             true /*IsSingleScalar*/, nullptr /*Mask*/, {},
1656             *WidenStoreR /*Metadata*/);
1657         ScalarStore->insertBefore(WidenStoreR);
1658         WidenStoreR->eraseFromParent();
1659         continue;
1660       }
1661 
1662       auto *RepOrWidenR = dyn_cast<VPRecipeWithIRFlags>(&R);
1663       if (RepR && isa<StoreInst>(RepR->getUnderlyingInstr()) &&
1664           vputils::isSingleScalar(RepR->getOperand(1))) {
1665         auto *Clone = new VPReplicateRecipe(
1666             RepOrWidenR->getUnderlyingInstr(), RepOrWidenR->operands(),
1667             true /*IsSingleScalar*/, nullptr /*Mask*/, *RepR /*Flags*/,
1668             *RepR /*Metadata*/, RepR->getDebugLoc());
1669         Clone->insertBefore(RepOrWidenR);
1670         VPBuilder Builder(Clone);
1671         VPValue *ExtractOp = Clone->getOperand(0);
1672         if (vputils::isUniformAcrossVFsAndUFs(RepR->getOperand(1)))
1673           ExtractOp =
1674               Builder.createNaryOp(VPInstruction::ExtractLastPart, ExtractOp);
1675         ExtractOp =
1676             Builder.createNaryOp(VPInstruction::ExtractLastLane, ExtractOp);
1677         Clone->setOperand(0, ExtractOp);
1678         RepR->eraseFromParent();
1679         continue;
1680       }
1681 
1682       // Skip recipes that aren't single scalars.
1683       if (!RepOrWidenR || !vputils::isSingleScalar(RepOrWidenR))
1684         continue;
1685 
1686       // Skip recipes for which conversion to single-scalar does introduce
1687       // additional broadcasts. No extra broadcasts are needed, if either only
1688       // the scalars of the recipe are used, or at least one of the operands
