566 
567   for (VPBasicBlock *VPBB : WorkList) {
568     VPBasicBlock *PredVPBB = cast<VPBasicBlock>(VPBB->getSinglePredecessor());
569     for (VPRecipeBase &R : make_early_inc_range(*VPBB))
570       R.moveBefore(*PredVPBB, PredVPBB->end());
