728   VPCanonicalIVPHIRecipe *CanonicalIV = LoopRegion->getCanonicalIV();
729   VPSingleDefRecipe *BaseIV = Builder.createDerivedIV(
730       Kind, FPBinOp, StartV, CanonicalIV, Step, "offset.idx");
