 940 static VPValue *optimizeEarlyExitInductionUser(VPlan &Plan,
 941                                                VPTypeAnalysis &TypeInfo,
 942                                                VPBlockBase *PredVPBB,
 943                                                VPValue *Op,
 944                                                PredicatedScalarEvolution &PSE) {
