3739 /// Expand a VPWidenPointerInductionRecipe into executable recipes, for the
3740 /// initial value, phi and backedge value. In the following example:
3741 ///
3742 ///  <x1> vector loop: {
3743 ///    vector.body:
3744 ///      EMIT ir<%ptr.iv> = WIDEN-POINTER-INDUCTION %start, %step, %vf
3745 ///      ...
3746 ///      EMIT branch-on-count ...
3747 ///  }
3748 ///
3749 /// WIDEN-POINTER-INDUCTION will get expanded to:
3750 ///
3751 ///  <x1> vector loop: {
3752 ///    vector.body:
3753 ///      EMIT-SCALAR %pointer.phi = phi %start, %ptr.ind
3754 ///      EMIT %mul = mul %stepvector, %step
3755 ///      EMIT %vector.gep = wide-ptradd %pointer.phi, %mul
3756 ///      ...
3757 ///      EMIT %ptr.ind = ptradd %pointer.phi, %vf
3758 ///      EMIT branch-on-count ...
3759 ///  }
3760 static void expandVPWidenPointerInduction(VPWidenPointerInductionRecipe *R,
3761                                           VPTypeAnalysis &TypeInfo) {
3762   VPlan *Plan = R->getParent()->getPlan();
3763   VPValue *Start = R->getStartValue();
3764   VPValue *Step = R->getStepValue();
3765   VPValue *VF = R->getVFValue();
3766 
3767   assert(R->getInductionDescriptor().getKind() ==
3768              InductionDescriptor::IK_PtrInduction &&
3769          "Not a pointer induction according to InductionDescriptor!");
3770   assert(TypeInfo.inferScalarType(R)->isPointerTy() && "Unexpected type.");
3771   assert(!R->onlyScalarsGenerated(Plan->hasScalableVF()) &&
3772          "Recipe should have been replaced");
3773 
3774   VPBuilder Builder(R);
3775   DebugLoc DL = R->getDebugLoc();
3776 
3777   // Build a scalar pointer phi.
3778   VPPhi *ScalarPtrPhi = Builder.createScalarPhi(Start, DL, "pointer.phi");
3779 
3780   // Create actual address geps that use the pointer phi as base and a
3781   // vectorized version of the step value (<step*0, ..., step*N>) as offset.
3782   Builder.setInsertPoint(R->getParent(), R->getParent()->getFirstNonPhi());
3783   Type *StepTy = TypeInfo.inferScalarType(Step);
3784   VPValue *Offset = Builder.createNaryOp(VPInstruction::StepVector, {}, StepTy);
3785   Offset = Builder.createOverflowingOp(Instruction::Mul, {Offset, Step});
3786   VPValue *PtrAdd =
3787       Builder.createWidePtrAdd(ScalarPtrPhi, Offset, DL, "vector.gep");
3788   R->replaceAllUsesWith(PtrAdd);
3789 
3790   // Create the backedge value for the scalar pointer phi.
3791   VPBasicBlock *ExitingBB = Plan->getVectorLoopRegion()->getExitingBasicBlock();
3792   Builder.setInsertPoint(ExitingBB, ExitingBB->getTerminator()->getIterator());
3793   VF = Builder.createScalarZExtOrTrunc(VF, StepTy, TypeInfo.inferScalarType(VF),
3794                                        DL);
3795   VPValue *Inc = Builder.createOverflowingOp(Instruction::Mul, {Step, VF});
3796 
3797   VPValue *InductionGEP =
3798       Builder.createPtrAdd(ScalarPtrPhi, Inc, DL, "ptr.ind");
3799   ScalarPtrPhi->addOperand(InductionGEP);
3800 }
