3814 void VPlanTransforms::expandBranchOnTwoConds(VPlan &Plan) {
3815   SmallVector<VPInstruction *> WorkList;
3816   // The transform runs after dissolving loop regions, so all VPBasicBlocks
3817   // terminated with BranchOnTwoConds are reached via a shallow traversal.
3818   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
3819            vp_depth_first_shallow(Plan.getEntry()))) {
3820     if (!VPBB->empty() && match(&VPBB->back(), m_BranchOnTwoConds()))
3821       WorkList.push_back(cast<VPInstruction>(&VPBB->back()));
3822   }
3823 
3824   // Expand BranchOnTwoConds instructions into explicit CFG with two new
3825   // single-condition branches:
3826   // 1. A branch that replaces BranchOnTwoConds, jumps to the first successor if
3827   //    the first condition is true, and otherwise jumps to a new interim block.
3828   // 2. A branch that ends the interim block, jumps to the second successor if
3829   //    the second condition is true, and otherwise jumps to the third
3830   //    successor.
3831   for (VPInstruction *Br : WorkList) {
3832     assert(Br->getNumOperands() == 2 &&
3833            "BranchOnTwoConds must have exactly 2 conditions");
3834     DebugLoc DL = Br->getDebugLoc();
3835     VPBasicBlock *BrOnTwoCondsBB = Br->getParent();
3836     const auto Successors = to_vector(BrOnTwoCondsBB->getSuccessors());
3837     assert(Successors.size() == 3 &&
3838            "BranchOnTwoConds must have exactly 3 successors");
3839 
3840     for (VPBlockBase *Succ : Successors)
3841       VPBlockUtils::disconnectBlocks(BrOnTwoCondsBB, Succ);
3842 
3843     VPValue *Cond0 = Br->getOperand(0);
3844     VPValue *Cond1 = Br->getOperand(1);
3845     VPBlockBase *Succ0 = Successors[0];
3846     VPBlockBase *Succ1 = Successors[1];
3847     VPBlockBase *Succ2 = Successors[2];
3848     assert(!Succ0->getParent() && !Succ1->getParent() && !Succ2->getParent() &&
3849            !BrOnTwoCondsBB->getParent() && "regions must already be dissolved");
3850 
3851     VPBasicBlock *InterimBB =
3852         Plan.createVPBasicBlock(BrOnTwoCondsBB->getName() + ".interim");
3853 
3854     VPBuilder(BrOnTwoCondsBB)
3855         .createNaryOp(VPInstruction::BranchOnCond, {Cond0}, DL);
3856     VPBlockUtils::connectBlocks(BrOnTwoCondsBB, Succ0);
3857     VPBlockUtils::connectBlocks(BrOnTwoCondsBB, InterimBB);
3858 
3859     VPBuilder(InterimBB).createNaryOp(VPInstruction::BranchOnCond, {Cond1}, DL);
3860     VPBlockUtils::connectBlocks(InterimBB, Succ1);
3861     VPBlockUtils::connectBlocks(InterimBB, Succ2);
3862     Br->eraseFromParent();
3863   }
3864 }
