4350 static void tryToCreateAbstractReductionRecipe(VPReductionRecipe *Red,
4351                                                VPCostContext &Ctx,
4352                                                VFRange &Range) {
4353   VPExpressionRecipe *AbstractR = nullptr;
4354   auto IP = std::next(Red->getIterator());
4355   auto *VPBB = Red->getParent();
4356   if (auto *MulAcc = tryToMatchAndCreateMulAccumulateReduction(Red, Ctx, Range))
4357     AbstractR = MulAcc;
4358   else if (auto *ExtRed = tryToMatchAndCreateExtendedReduction(Red, Ctx, Range))
4359     AbstractR = ExtRed;
4360   // Cannot create abstract inloop reduction recipes.
4361   if (!AbstractR)
4362     return;
4363 
4364   AbstractR->insertBefore(*VPBB, IP);
4365   Red->replaceAllUsesWith(AbstractR);
