4388   if (Plan.getOrCreateBackedgeTakenCount()->getNumUsers() > 0)
4389     VPValues.push_back(Plan.getOrCreateBackedgeTakenCount());
4390   append_range(VPValues, Plan.getLiveIns());
4391   for (VPRecipeBase &R : *Plan.getEntry())
4392     append_range(VPValues, R.definedValues());
