4394   auto *VectorPreheader = Plan.getVectorPreheader();
4395   for (VPValue *VPV : VPValues) {
4396     if (vputils::onlyScalarValuesUsed(VPV) ||
4397         (isa<VPIRValue>(VPV) && isa<Constant>(VPV->getLiveInIRValue())))
4398       continue;
4399 
4400     // Add explicit broadcast at the insert point that dominates all users.
4401     VPBasicBlock *HoistBlock = VectorPreheader;
4402     VPBasicBlock::iterator HoistPoint = VectorPreheader->end();
4403     for (VPUser *User : VPV->users()) {
4404       if (User->usesScalars(VPV))
4405         continue;
4406       if (cast<VPRecipeBase>(User)->getParent() == VectorPreheader)
4407         HoistPoint = HoistBlock->begin();
4408       else
4409         assert(VPDT.dominates(VectorPreheader,
4410                               cast<VPRecipeBase>(User)->getParent()) &&
4411                "All users must be in the vector preheader or dominated by it");
4412     }
4413 
4414     VPBuilder Builder(cast<VPBasicBlock>(HoistBlock), HoistPoint);
4415     auto *Broadcast = Builder.createNaryOp(VPInstruction::Broadcast, {VPV});
4416     VPV->replaceUsesWithIf(Broadcast,
4417                            [VPV, Broadcast](VPUser &U, unsigned Idx) {
4418                              return Broadcast != &U && !U.usesScalars(VPV);
4419                            });
