4423 void VPlanTransforms::hoistInvariantLoads(VPlan &Plan) {
4424   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
4425 
4426   // Collect candidate loads with invariant addresses and noalias scopes
4427   // metadata and memory-writing recipes with noalias metadata.
4428   SmallVector<std::pair<VPRecipeBase *, MemoryLocation>> CandidateLoads;
4429   SmallVector<MemoryLocation> Stores;
4430   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
4431            vp_depth_first_shallow(LoopRegion->getEntry()))) {
4432     for (VPRecipeBase &R : *VPBB) {
4433       // Only handle single-scalar replicated loads with invariant addresses.
4434       if (auto *RepR = dyn_cast<VPReplicateRecipe>(&R)) {
4435         if (RepR->isPredicated() || !RepR->isSingleScalar() ||
4436             RepR->getOpcode() != Instruction::Load)
4437           continue;
4438 
4439         VPValue *Addr = RepR->getOperand(0);
4440         if (Addr->isDefinedOutsideLoopRegions()) {
4441           MemoryLocation Loc = *vputils::getMemoryLocation(*RepR);
4442           if (!Loc.AATags.Scope)
4443             continue;
4444           CandidateLoads.push_back({RepR, Loc});
4445         }
4446       }
4447       if (R.mayWriteToMemory()) {
4448         auto Loc = vputils::getMemoryLocation(R);
4449         if (!Loc || !Loc->AATags.Scope || !Loc->AATags.NoAlias)
4450           return;
4451         Stores.push_back(*Loc);
4452       }
4453     }
4454   }
4455 
4456   VPBasicBlock *Preheader = Plan.getVectorPreheader();
4457   for (auto &[LoadRecipe, LoadLoc] : CandidateLoads) {
4458     // Hoist the load to the preheader if it doesn't alias with any stores
4459     // according to the noalias metadata. Other loads should have been hoisted
4460     // by other passes
4461     const AAMDNodes &LoadAA = LoadLoc.AATags;
4462     if (all_of(Stores, [&](const MemoryLocation &StoreLoc) {
4463           return !ScopedNoAliasAAResult::mayAliasInScopes(
4464               LoadAA.Scope, StoreLoc.AATags.NoAlias);
4465         })) {
4466       LoadRecipe->moveBefore(*Preheader, Preheader->getFirstNonPhi());
4467     }
4468   }
4469 }
