4566 void VPlanTransforms::hoistPredicatedLoads(VPlan &Plan,
4567                                            PredicatedScalarEvolution &PSE,
4568                                            const Loop *L) {
4569   auto Groups =
4570       collectComplementaryPredicatedMemOps<Instruction::Load>(Plan, PSE, L);
4571   if (Groups.empty())
4572     return;
4573 
4574   VPDominatorTree VPDT(Plan);
4575 
4576   // Process each group of loads.
4577   for (auto &Group : Groups) {
4578     // Sort loads by dominance order, with earliest (most dominating) first.
4579     sort(Group, [&VPDT](VPReplicateRecipe *A, VPReplicateRecipe *B) {
4580       return VPDT.properlyDominates(A, B);
4581     });
4582 
4583     // Try to use the earliest (most dominating) load to replace all others.
4584     VPReplicateRecipe *EarliestLoad = Group[0];
4585     VPBasicBlock *FirstBB = EarliestLoad->getParent();
4586     VPBasicBlock *LastBB = Group.back()->getParent();
4587 
4588     // Check that the load doesn't alias with stores between first and last.
4589     auto LoadLoc = vputils::getMemoryLocation(*EarliestLoad);
4590     if (!LoadLoc || !canHoistOrSinkWithNoAliasCheck(*LoadLoc, FirstBB, LastBB))
4591       continue;
4592 
4593     // Collect common metadata from all loads in the group.
4594     VPIRMetadata CommonMetadata = getCommonMetadata(Group);
4595 
4596     // Find the load with minimum alignment to use.
4597     auto *LoadWithMinAlign = findRecipeWithMinAlign<LoadInst>(Group);
4598 
4599     // Create an unpredicated version of the earliest load with common
4600     // metadata.
4601     auto *UnpredicatedLoad = new VPReplicateRecipe(
4602         LoadWithMinAlign->getUnderlyingInstr(), {EarliestLoad->getOperand(0)},
4603         /*IsSingleScalar=*/false, /*Mask=*/nullptr, *EarliestLoad,
4604         CommonMetadata);
4605 
4606     UnpredicatedLoad->insertBefore(EarliestLoad);
4607 
4608     // Replace all loads in the group with the unpredicated load.
4609     for (VPReplicateRecipe *Load : Group) {
4610       Load->replaceAllUsesWith(UnpredicatedLoad);
4611       Load->eraseFromParent();
4612     }
4613   }
