4617 canSinkStoreWithNoAliasCheck(ArrayRef<VPReplicateRecipe *> StoresToSink,
4618                              PredicatedScalarEvolution &PSE, const Loop &L,
4619                              VPTypeAnalysis &TypeInfo) {
