4635 void VPlanTransforms::sinkPredicatedStores(VPlan &Plan,
4636                                            PredicatedScalarEvolution &PSE,
4637                                            const Loop *L) {
4638   auto Groups =
4639       collectComplementaryPredicatedMemOps<Instruction::Store>(Plan, PSE, L);
4640   if (Groups.empty())
4641     return;
4642 
4643   VPDominatorTree VPDT(Plan);
4644   VPTypeAnalysis TypeInfo(Plan);
