4650 
4651     if (!canSinkStoreWithNoAliasCheck(Group, PSE, *L, TypeInfo))
4652       continue;
4653 
4654     // Use the last (most dominated) store's location for the unconditional
4655     // store.
4656     VPReplicateRecipe *LastStore = Group.back();
4657     VPBasicBlock *InsertBB = LastStore->getParent();
4658 
4659     // Collect common alias metadata from all stores in the group.
4660     VPIRMetadata CommonMetadata = getCommonMetadata(Group);
4661 
4662     // Build select chain for stored values.
4663     VPValue *SelectedValue = Group[0]->getOperand(0);
4664     VPBuilder Builder(InsertBB, LastStore->getIterator());
4665 
4666     for (unsigned I = 1; I < Group.size(); ++I) {
4667       VPValue *Mask = Group[I]->getMask();
4668       VPValue *Value = Group[I]->getOperand(0);
4669       SelectedValue = Builder.createSelect(Mask, Value, SelectedValue,
4670                                            Group[I]->getDebugLoc());
