4677     auto *UnpredicatedStore =
4678         new VPReplicateRecipe(StoreWithMinAlign->getUnderlyingInstr(),
4679                               {SelectedValue, LastStore->getOperand(1)},
4680                               /*IsSingleScalar=*/false,
4681                               /*Mask=*/nullptr, *LastStore, CommonMetadata);
4682     UnpredicatedStore->insertBefore(*InsertBB, LastStore->getIterator());
4683 
