4706   // Materialize vector trip counts for constants early if it can simply
4707   // be computed as (Original TC / VF * UF) * VF * UF.
4708   // TODO: Compute vector trip counts for loops requiring a scalar epilogue and
4709   // tail-folded loops.
4710   ScalarEvolution &SE = *PSE.getSE();
