4715   auto VecTCScev = SE.getMulExpr(SE.getUDivExpr(TCScev, VFxUF), VFxUF);
4716   if (auto *ConstVecTC = dyn_cast<SCEVConstant>(VecTCScev))
4717     Plan.getVectorTripCount().setUnderlyingValue(ConstVecTC->getValue());
