1824 /// Optimize the width of vector induction variables in \p Plan based on a known
1825 /// constant Trip Count, \p BestVF and \p BestUF.
1826 static bool optimizeVectorInductionWidthForTCAndVFUF(VPlan &Plan,
1827                                                      ElementCount BestVF,
1828                                                      unsigned BestUF) {
1829   // Only proceed if we have not completely removed the vector region.
1830   if (!Plan.getVectorLoopRegion())
1831     return false;
1832 
1833   const APInt *TC;
1834   if (!BestVF.isFixed() || !match(Plan.getTripCount(), m_APInt(TC)))
1835     return false;
1836 
1837   // Calculate the minimum power-of-2 bit width that can fit the known TC, VF
1838   // and UF. Returns at least 8.
1839   auto ComputeBitWidth = [](APInt TC, uint64_t Align) {
1840     APInt AlignedTC =
1841         Align * APIntOps::RoundingUDiv(TC, APInt(TC.getBitWidth(), Align),
1842                                        APInt::Rounding::UP);
1843     APInt MaxVal = AlignedTC - 1;
1844     return std::max<unsigned>(PowerOf2Ceil(MaxVal.getActiveBits()), 8);
1845   };
1846   unsigned NewBitWidth =
1847       ComputeBitWidth(*TC, BestVF.getKnownMinValue() * BestUF);
1848 
1849   LLVMContext &Ctx = Plan.getContext();
1850   auto *NewIVTy = IntegerType::get(Ctx, NewBitWidth);
1851 
1852   bool MadeChange = false;
1853 
1854   VPBasicBlock *HeaderVPBB = Plan.getVectorLoopRegion()->getEntryBasicBlock();
1855   for (VPRecipeBase &Phi : HeaderVPBB->phis()) {
1856     auto *WideIV = dyn_cast<VPWidenIntOrFpInductionRecipe>(&Phi);
1857 
1858     // Currently only handle canonical IVs as it is trivial to replace the start
1859     // and stop values, and we currently only perform the optimization when the
1860     // IV has a single use.
1861     if (!WideIV || !WideIV->isCanonical() ||
1862         WideIV->hasMoreThanOneUniqueUser() ||
1863         NewIVTy == WideIV->getScalarType())
1864       continue;
1865 
1866     // Currently only handle cases where the single user is a header-mask
1867     // comparison with the backedge-taken-count.
1868     VPUser *SingleUser = WideIV->getSingleUser();
1869     if (!SingleUser ||
1870         !match(SingleUser, m_ICmp(m_Specific(WideIV),
1871                                   m_Broadcast(m_Specific(
1872                                       Plan.getOrCreateBackedgeTakenCount())))))
1873       continue;
1874 
1875     // Update IV operands and comparison bound to use new narrower type.
1876     auto *NewStart = Plan.getConstantInt(NewIVTy, 0);
1877     WideIV->setStartValue(NewStart);
1878     auto *NewStep = Plan.getConstantInt(NewIVTy, 1);
1879     WideIV->setStepValue(NewStep);
1880 
1881     auto *NewBTC = new VPWidenCastRecipe(
1882         Instruction::Trunc, Plan.getOrCreateBackedgeTakenCount(), NewIVTy,
1883         nullptr, VPIRFlags::getDefaultFlags(Instruction::Trunc));
1884     Plan.getVectorPreheader()->appendRecipe(NewBTC);
1885     auto *Cmp = cast<VPInstruction>(WideIV->getSingleUser());
1886     Cmp->setOperand(1, NewBTC);
1887 
1888     MadeChange = true;
1889   }
1890 
1891   return MadeChange;
1892 }
