1927 /// Try to replace multiple active lane masks used for control flow with
1928 /// a single, wide active lane mask instruction followed by multiple
1929 /// extract subvector intrinsics. This applies to the active lane mask
1930 /// instructions both in the loop and in the preheader.
1931 /// Incoming values of all ActiveLaneMaskPHIs are updated to use the
1932 /// new extracts from the first active lane mask, which has it's last
1933 /// operand (multiplier) set to UF.
1934 static bool tryToReplaceALMWithWideALM(VPlan &Plan, ElementCount VF,
1935                                        unsigned UF) {
1936   if (!EnableWideActiveLaneMask || !VF.isVector() || UF == 1)
1937     return false;
1938 
1939   VPRegionBlock *VectorRegion = Plan.getVectorLoopRegion();
1940   VPBasicBlock *ExitingVPBB = VectorRegion->getExitingBasicBlock();
1941   auto *Term = &ExitingVPBB->back();
1942 
1943   using namespace llvm::VPlanPatternMatch;
1944   if (!match(Term, m_BranchOnCond(m_Not(m_ActiveLaneMask(
1945                        m_VPValue(), m_VPValue(), m_VPValue())))))
1946     return false;
1947 
1948   auto *Header = cast<VPBasicBlock>(VectorRegion->getEntry());
1949   LLVMContext &Ctx = Plan.getContext();
1950 
1951   auto ExtractFromALM = [&](VPInstruction *ALM,
1952                             SmallVectorImpl<VPValue *> &Extracts) {
1953     DebugLoc DL = ALM->getDebugLoc();
1954     for (unsigned Part = 0; Part < UF; ++Part) {
1955       SmallVector<VPValue *> Ops;
1956       Ops.append({ALM, Plan.getOrAddLiveIn(
1957                            ConstantInt::get(IntegerType::getInt64Ty(Ctx),
1958                                             VF.getKnownMinValue() * Part))});
1959       auto *Ext =
1960           new VPWidenIntrinsicRecipe(Intrinsic::vector_extract, Ops,
1961                                      IntegerType::getInt1Ty(Ctx), {}, {}, DL);
1962       Extracts[Part] = Ext;
1963       Ext->insertAfter(ALM);
1964     }
1965   };
1966 
1967   // Create a list of each active lane mask phi, ordered by unroll part.
1968   SmallVector<VPActiveLaneMaskPHIRecipe *> Phis(UF, nullptr);
1969   for (VPRecipeBase &R : Header->phis()) {
1970     auto *Phi = dyn_cast<VPActiveLaneMaskPHIRecipe>(&R);
1971     if (!Phi)
1972       continue;
1973     VPValue *Index = nullptr;
1974     match(Phi->getBackedgeValue(),
1975           m_ActiveLaneMask(m_VPValue(Index), m_VPValue(), m_VPValue()));
1976     assert(Index && "Expected index from ActiveLaneMask instruction");
1977 
1978     uint64_t Part;
1979     if (match(Index,
1980               m_VPInstruction<VPInstruction::CanonicalIVIncrementForPart>(
1981                   m_VPValue(), m_ConstantInt(Part))))
1982       Phis[Part] = Phi;
1983     else
1984       // Anything other than a CanonicalIVIncrementForPart is part 0
1985       Phis[0] = Phi;
1986   }
1987 
1988   assert(all_of(Phis, [](VPActiveLaneMaskPHIRecipe *Phi) { return Phi; }) &&
1989          "Expected one VPActiveLaneMaskPHIRecipe for each unroll part");
1990 
1991   auto *EntryALM = cast<VPInstruction>(Phis[0]->getStartValue());
1992   auto *LoopALM = cast<VPInstruction>(Phis[0]->getBackedgeValue());
1993 
1994   assert((EntryALM->getOpcode() == VPInstruction::ActiveLaneMask &&
1995           LoopALM->getOpcode() == VPInstruction::ActiveLaneMask) &&
1996          "Expected incoming values of Phi to be ActiveLaneMasks");
1997 
1998   // When using wide lane masks, the return type of the get.active.lane.mask
1999   // intrinsic is VF x UF (last operand).
2000   VPValue *ALMMultiplier = Plan.getConstantInt(64, UF);
2001   EntryALM->setOperand(2, ALMMultiplier);
2002   LoopALM->setOperand(2, ALMMultiplier);
2003 
2004   // Create UF x extract vectors and insert into preheader.
2005   SmallVector<VPValue *> EntryExtracts(UF);
2006   ExtractFromALM(EntryALM, EntryExtracts);
2007 
2008   // Create UF x extract vectors and insert before the loop compare & branch,
2009   // updating the compare to use the first extract.
2010   SmallVector<VPValue *> LoopExtracts(UF);
2011   ExtractFromALM(LoopALM, LoopExtracts);
2012   VPInstruction *Not = cast<VPInstruction>(Term->getOperand(0));
2013   Not->setOperand(0, LoopExtracts[0]);
2014 
2015   // Update the incoming values of active lane mask phis.
2016   for (unsigned Part = 0; Part < UF; ++Part) {
2017     Phis[Part]->setStartValue(EntryExtracts[Part]);
2018     Phis[Part]->setBackedgeValue(LoopExtracts[Part]);
2019   }
2020 
