1894 /// Return true if \p Cond is known to be true for given \p BestVF and \p
1895 /// BestUF.
1896 static bool isConditionTrueViaVFAndUF(VPValue *Cond, VPlan &Plan,
1897                                       ElementCount BestVF, unsigned BestUF,
1898                                       PredicatedScalarEvolution &PSE) {
1899   if (match(Cond, m_BinaryOr(m_VPValue(), m_VPValue())))
1900     return any_of(Cond->getDefiningRecipe()->operands(), [&Plan, BestVF, BestUF,
1901                                                           &PSE](VPValue *C) {
1902       return isConditionTrueViaVFAndUF(C, Plan, BestVF, BestUF, PSE);
1903     });
1904 
1905   auto *CanIV = Plan.getVectorLoopRegion()->getCanonicalIV();
1906   if (!match(Cond, m_SpecificICmp(CmpInst::ICMP_EQ,
1907                                   m_Specific(CanIV->getBackedgeValue()),
1908                                   m_Specific(&Plan.getVectorTripCount()))))
1909     return false;
1910 
1911   // The compare checks CanIV + VFxUF == vector trip count. The vector trip
1912   // count is not conveniently available as SCEV so far, so we compare directly
1913   // against the original trip count. This is stricter than necessary, as we
1914   // will only return true if the trip count == vector trip count.
1915   const SCEV *VectorTripCount =
1916       vputils::getSCEVExprForVPValue(&Plan.getVectorTripCount(), PSE);
1917   if (isa<SCEVCouldNotCompute>(VectorTripCount))
1918     VectorTripCount = vputils::getSCEVExprForVPValue(Plan.getTripCount(), PSE);
1919   assert(!isa<SCEVCouldNotCompute>(VectorTripCount) &&
1920          "Trip count SCEV must be computable");
1921   ScalarEvolution &SE = *PSE.getSE();
1922   ElementCount NumElements = BestVF.multiplyCoefficientBy(BestUF);
1923   const SCEV *C = SE.getElementCount(VectorTripCount->getType(), NumElements);
1924   return SE.isKnownPredicate(CmpInst::ICMP_EQ, VectorTripCount, C);
1925 }
