3995                                                  VPBasicBlock *EarlyExitVPBB,
3996                                                  VPlan &Plan,
3997                                                  VPBasicBlock *HeaderVPBB,
3998                                                  VPBasicBlock *LatchVPBB) {
3999   auto *MiddleVPBB = cast<VPBasicBlock>(LatchVPBB->getSuccessors()[0]);
4000   if (!EarlyExitVPBB->getSinglePredecessor() &&
4001       EarlyExitVPBB->getPredecessors()[1] == MiddleVPBB) {
4002     assert(EarlyExitVPBB->getNumPredecessors() == 2 &&
4003            EarlyExitVPBB->getPredecessors()[0] == EarlyExitingVPBB &&
4004            "unsupported early exit VPBB");
4005     // Early exit operand should always be last phi operand. If EarlyExitVPBB
4006     // has two predecessors and EarlyExitingVPBB is the first, swap the operands
4007     // of the phis.
4008     for (VPRecipeBase &R : EarlyExitVPBB->phis())
4009       cast<VPIRPhi>(&R)->swapOperands();
4010   }
4011 
4012   VPBuilder Builder(LatchVPBB->getTerminator());
4013   VPBlockBase *TrueSucc = EarlyExitingVPBB->getSuccessors()[0];
4014   assert(match(EarlyExitingVPBB->getTerminator(), m_BranchOnCond()) &&
4015          "Terminator must be be BranchOnCond");
4016   VPValue *CondOfEarlyExitingVPBB =
4017       EarlyExitingVPBB->getTerminator()->getOperand(0);
4018   auto *CondToEarlyExit = TrueSucc == EarlyExitVPBB
4019                               ? CondOfEarlyExitingVPBB
4020                               : Builder.createNot(CondOfEarlyExitingVPBB);
4021 
4022   // Create a BranchOnTwoConds in the latch that branches to:
4023   // [0] vector.early.exit, [1] middle block, [2] header (continue looping).
4024   VPValue *IsEarlyExitTaken =
4025       Builder.createNaryOp(VPInstruction::AnyOf, {CondToEarlyExit});
4026   VPBasicBlock *VectorEarlyExitVPBB =
4027       Plan.createVPBasicBlock("vector.early.exit");
4028   VectorEarlyExitVPBB->setParent(EarlyExitVPBB->getParent());
4029 
4030   VPBlockUtils::connectBlocks(VectorEarlyExitVPBB, EarlyExitVPBB);
4031 
4032   // Update the exit phis in the early exit block.
4033   VPBuilder MiddleBuilder(MiddleVPBB);
4034   VPBuilder EarlyExitB(VectorEarlyExitVPBB);
4035   for (VPRecipeBase &R : EarlyExitVPBB->phis()) {
4036     auto *ExitIRI = cast<VPIRPhi>(&R);
4037     // Early exit operand should always be last, i.e., 0 if EarlyExitVPBB has
4038     // a single predecessor and 1 if it has two.
4039     unsigned EarlyExitIdx = ExitIRI->getNumOperands() - 1;
4040     if (ExitIRI->getNumOperands() != 1) {
4041       // The first of two operands corresponds to the latch exit, via MiddleVPBB
4042       // predecessor. Extract its final lane.
4043       ExitIRI->extractLastLaneOfLastPartOfFirstOperand(MiddleBuilder);
4044     }
4045 
4046     VPValue *IncomingFromEarlyExit = ExitIRI->getOperand(EarlyExitIdx);
4047     if (!isa<VPIRValue>(IncomingFromEarlyExit)) {
4048       // Update the incoming value from the early exit.
4049       VPValue *FirstActiveLane = EarlyExitB.createNaryOp(
4050           VPInstruction::FirstActiveLane, {CondToEarlyExit},
4051           DebugLoc::getUnknown(), "first.active.lane");
4052       IncomingFromEarlyExit = EarlyExitB.createNaryOp(
4053           VPInstruction::ExtractLane, {FirstActiveLane, IncomingFromEarlyExit},
4054           DebugLoc::getUnknown(), "early.exit.value");
4055       ExitIRI->setOperand(EarlyExitIdx, IncomingFromEarlyExit);
4056     }
4057   }
4058 
4059   // Replace the conditional branch controlling the latch exit from the vector
4060   // loop with a multi-conditional branch exiting to vector early exit if the
4061   // early exit has been taken, exiting to middle block if the original
4062   // condition of the vector latch is true, otherwise continuing back to header.
4063   auto *LatchExitingBranch = cast<VPInstruction>(LatchVPBB->getTerminator());
4064   assert(LatchExitingBranch->getOpcode() == VPInstruction::BranchOnCount &&
4065          "Unexpected terminator");
4066   auto *IsLatchExitTaken =
4067       Builder.createICmp(CmpInst::ICMP_EQ, LatchExitingBranch->getOperand(0),
4068                          LatchExitingBranch->getOperand(1));
4069 
4070   DebugLoc LatchDL = LatchExitingBranch->getDebugLoc();
4071   LatchExitingBranch->eraseFromParent();
4072 
4073   Builder.setInsertPoint(LatchVPBB);
4074   Builder.createNaryOp(VPInstruction::BranchOnTwoConds,
4075                        {IsEarlyExitTaken, IsLatchExitTaken}, LatchDL);
4076   LatchVPBB->clearSuccessors();
4077   LatchVPBB->setSuccessors({VectorEarlyExitVPBB, MiddleVPBB, HeaderVPBB});
4078   VectorEarlyExitVPBB->setPredecessors({LatchVPBB});
